package org.example.matrix.services;

import org.apache.sling.api.resource.Resource;
import org.apache.sling.api.resource.ResourceResolver;
import org.apache.sling.api.resource.ValueMap;

public class MatrixNavigator {

    public void navigateTheMatrix(ResourceResolver resolver) {
        // Get a resource by path
        Resource neo = resolver.getResource("/content/sling-matrix/agents/neo");

        if (neo != null) {
            // Access properties via ValueMap
            ValueMap props = neo.getValueMap();
            String role = props.get("role", String.class);
            Boolean isTheOne = props.get("isTheOne", false);

            // Navigate to child resources
            Resource abilities = neo.getChild("abilities");

            // Iterate through children
            for (Resource skill : abilities.getChildren()) {
                String skillName = skill.getName();
                System.out.println("Skill downloaded: " + skillName);
            }

            // Adapt resource to specific type
            MatrixAgent agent = neo.adaptTo(MatrixAgent.class);
        }
    }
}
